import{_ as t,o as i,c as g,a0 as h}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Thêm người dùng","description":"","frontmatter":{"title":"Thêm người dùng"},"headers":[],"relativePath":"adding-users.md","filePath":"adding-users.md"}'),o={name:"adding-users.md"};function a(r,n,c,s,l,e){return i(),g("div",null,[...n[0]||(n[0]=[h('<h1 id="them-nguoi-dung" tabindex="-1">Thêm người dùng <a class="header-anchor" href="#them-nguoi-dung" aria-label="Permalink to &quot;Thêm người dùng&quot;">​</a></h1><p>Việc thêm người dùng mới vào ABNERP được thực hiện thông qua giao diện <strong>Người dùng (User)</strong>. Quản trị viên có thể tạo, cấu hình và phân quyền cho từng tài khoản người dùng một cách chi tiết.</p><h2 id="quan-ly-nguoi-dung" tabindex="-1">Quản lý người dùng <a class="header-anchor" href="#quan-ly-nguoi-dung" aria-label="Permalink to &quot;Quản lý người dùng&quot;">​</a></h2><p>Để thêm người dùng mới, vào <strong>Cài đặt &gt; Người dùng</strong> và nhấn <strong>Thêm Người dùng</strong>. Các thông tin cần nhập bao gồm:</p><ul><li><strong>Email</strong>: địa chỉ email của người dùng (dùng để đăng nhập)</li><li><strong>Tên đầy đủ</strong>: họ và tên của người dùng</li><li><strong>Tên người dùng</strong>: tên đăng nhập (nếu khác email)</li><li><strong>Mật khẩu</strong>: mật khẩu đăng nhập ban đầu</li><li><strong>Trạng thái</strong>: Kích hoạt hoặc Vô hiệu hóa tài khoản</li><li><strong>Chi nhánh</strong>: chi nhánh mặc định của người dùng</li></ul><p>Sau khi tạo, hệ thống sẽ gửi email kích hoạt tài khoản đến người dùng. Nếu muốn, quản trị viên có thể tạo tài khoản và đặt mật khẩu thủ công cho người dùng.</p><h2 id="vai-tro" tabindex="-1">Vai trò <a class="header-anchor" href="#vai-tro" aria-label="Permalink to &quot;Vai trò&quot;">​</a></h2><p><strong>Vai trò (Role)</strong> xác định quyền hạn của người dùng trong hệ thống. Mỗi người dùng có thể được gán một hoặc nhiều vai trò. Để gán vai trò:</p><ol><li>Mở hồ sơ người dùng</li><li>Chuyển đến phần <strong>Vai trò</strong></li><li>Thêm vai trò phù hợp với trách nhiệm của người dùng</li></ol><p>Các vai trò phổ biến:</p><ul><li><strong>System Manager</strong>: quản lý hệ thống và cấu hình</li><li><strong>Accounts User / Accounts Manager</strong>: nhân viên kế toán</li><li><strong>Sales User / Sales Manager</strong>: nhân viên bán hàng</li><li><strong>Purchase User / Purchase Manager</strong>: nhân viên mua hàng</li><li><strong>HR User / HR Manager</strong>: nhân viên nhân sự</li><li><strong>Stock User / Stock Manager</strong>: thủ kho và quản lý kho</li><li><strong>Employee</strong>: vai trò cơ bản cho tất cả nhân viên</li><li><strong>Customer</strong>: khách hàng truy cập cổng thông tin</li></ul><blockquote><p><strong>Lưu ý</strong>: Việc gán vai trò cần tuân thủ nguyên tắc phân tách nhiệm vụ — tránh giao vai trò mâu thuẫn cho cùng một người dùng (ví dụ: vừa được duyệt vừa được tạo mua hàng).</p></blockquote><h2 id="cai-đat-bao-mat" tabindex="-1">Cài đặt bảo mật <a class="header-anchor" href="#cai-đat-bao-mat" aria-label="Permalink to &quot;Cài đặt bảo mật&quot;">​</a></h2><p>Các thiết lập bảo mật bổ sung cho từng người dùng:</p><ul><li><strong>Xác thực hai yếu tố</strong>: bắt buộc hoặc tùy chọn</li><li><strong>API Access</strong>: cấp quyền truy cập API cho người dùng</li><li><strong>Desktop Access</strong>: hiển thị người dùng trên trình quản lý desktop</li><li><strong>Giới hạn đăng nhập</strong>: thiết lập thời gian cho phép đăng nhập</li></ul><h2 id="api-access" tabindex="-1">API Access <a class="header-anchor" href="#api-access" aria-label="Permalink to &quot;API Access&quot;">​</a></h2><p>Để cho phép người dùng tương tác với ABNERP qua API, bật tùy chọn <strong>API Access</strong> trong hồ sơ người dùng. Người dùng có API Access có thể:</p><ul><li>Tạo <strong>API Key</strong> và <strong>API Secret</strong> trong hồ sơ của họ</li><li>Sử dụng API Key để xác thực các yêu cầu API REST</li><li>Gọi các endpoint API tương ứng với quyền của vai trò được gán</li></ul><p>Sau khi thêm người dùng, hãy kiểm tra quyền truy cập bằng cách đăng nhập thử bằng tài khoản mới và xác nhận rằng tất cả chức năng cần thiết đều hoạt động đúng theo phân quyền đã thiết lập.</p>',19)])])}const p=t(o,[["render",a]]);export{d as __pageData,p as default};
